// ==UserScript==
// @name         预设对比助手
// @description  对比两个Chat Completion预设的prompt条目开关差异
// @version      2.3.0
// ==/UserScript==

var pcaC = {
    bg:'#0f0f14', card:'#1a1a24', card2:'#22202e',
    border:'#2a2030', pink:'#e8a0bf', pinkDim:'#9e6080',
    gold:'#d4a853', goldDim:'#a08030', text:'#d8d0e0',
    dim:'#7a6a8a', off:'#3a3a4a', danger:'#e06070',
    success:'#6ecf8a', input:'#16121e',
    diffAdd:'rgba(110,207,138,0.15)', diffAddBorder:'rgba(110,207,138,0.4)',
    diffDel:'rgba(224,96,112,0.15)', diffDelBorder:'rgba(224,96,112,0.4)',
    diffAddText:'#8eeaaa', diffDelText:'#f08090',
};

var pcaLogs = [];
function pcaLog(msg) {
    var t = new Date().toLocaleTimeString('zh-CN',{hour12:false});
    pcaLogs.push(t + ' ' + msg);
    if (pcaLogs.length > 300) pcaLogs.splice(0, pcaLogs.length - 300);
    console.log('[预设对比]', msg);
}
function pcaEsc(s) { var d = document.createElement('div'); d.textContent = s||''; return d.innerHTML; }
function pcaGetDoc() { try { return window.parent.document; } catch(e) { return document; } }
function pcaQ(sel) { return pcaGetDoc().querySelector(sel); }
function pcaGetHeaders() {
    var h = {'Content-Type':'application/json'};
    try { var ctx = SillyTavern.getContext(); if (typeof ctx.getRequestHeaders === 'function') Object.assign(h, ctx.getRequestHeaders()); } catch(e) {}
    return h;
}

/* ============================================================
 *  简易 Diff 算法（Myers 风格，行级别）
 * ============================================================ */
function pcaDiffLines(oldText, newText) {
    var oldLines = (oldText || '').split('\n');
    var newLines = (newText || '').split('\n');

    // LCS 构建表
    var m = oldLines.length, n = newLines.length;
    // 对于过长文本用简化策略
    if (m * n > 500000) {
        return pcaDiffSimple(oldLines, newLines);
    }

    var dp = [];
    for (var i = 0; i <= m; i++) {
        dp[i] = [];
        for (var j = 0; j <= n; j++) dp[i][j] = 0;
    }
    for (var i2 = 1; i2 <= m; i2++) {
        for (var j2 = 1; j2 <= n; j2++) {
            if (oldLines[i2-1] === newLines[j2-1]) dp[i2][j2] = dp[i2-1][j2-1] + 1;
            else dp[i2][j2] = Math.max(dp[i2-1][j2], dp[i2][j2-1]);
        }
    }

    // 回溯
    var result = [];
    var oi = m, ni = n;
    while (oi > 0 || ni > 0) {
        if (oi > 0 && ni > 0 && oldLines[oi-1] === newLines[ni-1]) {
            result.unshift({ type:'same', text:oldLines[oi-1] });
            oi--; ni--;
        } else if (ni > 0 && (oi === 0 || dp[oi][ni-1] >= dp[oi-1][ni])) {
            result.unshift({ type:'add', text:newLines[ni-1] });
            ni--;
        } else {
            result.unshift({ type:'del', text:oldLines[oi-1] });
            oi--;
        }
    }
    return result;
}

// 超长文本的简化diff：找出相同行、不同行
function pcaDiffSimple(oldLines, newLines) {
    var result = [];
    var oldSet = {};
    oldLines.forEach(function(l) { oldSet[l] = (oldSet[l]||0) + 1; });
    var newSet = {};
    newLines.forEach(function(l) { newSet[l] = (newSet[l]||0) + 1; });

    // 标记每行：如果在对方也存在就是same，否则add/del
    var oi = 0, ni = 0;
    while (oi < oldLines.length || ni < newLines.length) {
        if (oi < oldLines.length && ni < newLines.length && oldLines[oi] === newLines[ni]) {
            result.push({ type:'same', text:oldLines[oi] });
            oi++; ni++;
        } else if (oi < oldLines.length && (!newSet[oldLines[oi]] || newSet[oldLines[oi]] <= 0)) {
            result.push({ type:'del', text:oldLines[oi] });
            oi++;
        } else if (ni < newLines.length && (!oldSet[newLines[ni]] || oldSet[newLines[ni]] <= 0)) {
            result.push({ type:'add', text:newLines[ni] });
            ni++;
        } else {
            // 都有但位置不同，先输出del再add
            if (oi < oldLines.length) { result.push({ type:'del', text:oldLines[oi] }); oi++; }
            if (ni < newLines.length) { result.push({ type:'add', text:newLines[ni] }); ni++; }
        }
    }
    return result;
}

// 判断是否"完全重写"：相同行占比 < 20%
function pcaIsRewrite(diffResult) {
    if (diffResult.length === 0) return false;
    var same = 0, total = 0;
    diffResult.forEach(function(d) {
        if (d.text.trim()) { // 只计非空行
            total++;
            if (d.type === 'same') same++;
        }
    });
    if (total === 0) return false;
    return (same / total) < 0.2;
}

// 渲染diff为HTML
function pcaRenderDiffHTML(leftContent, rightContent) {
    if (!leftContent && !rightContent) {
        return '<div style="color:#555;padding:8px;">（两侧都是空内容）</div>';
    }
    if (!leftContent) {
        return '<div style="padding:8px;"><div style="color:'+pcaC.gold+';font-size:11px;margin-bottom:6px;font-weight:600;">📝 左侧为空，右侧全部为新增内容：</div>'
            + '<div style="background:'+pcaC.diffAdd+';border-left:3px solid '+pcaC.diffAddBorder+';padding:6px 10px;border-radius:4px;font-size:12px;line-height:1.6;color:'+pcaC.diffAddText+';white-space:pre-wrap;word-break:break-all;">'+pcaEsc(rightContent)+'</div></div>';
    }
    if (!rightContent) {
        return '<div style="padding:8px;"><div style="color:'+pcaC.gold+';font-size:11px;margin-bottom:6px;font-weight:600;">📝 右侧为空，左侧全部内容已删除：</div>'
            + '<div style="background:'+pcaC.diffDel+';border-left:3px solid '+pcaC.diffDelBorder+';padding:6px 10px;border-radius:4px;font-size:12px;line-height:1.6;color:'+pcaC.diffDelText+';white-space:pre-wrap;word-break:break-all;">'+pcaEsc(leftContent)+'</div></div>';
    }
    if (leftContent === rightContent) {
        return '<div style="color:'+pcaC.success+';padding:8px;font-size:13px;">✓ 内容完全相同</div>';
    }

    var diff = pcaDiffLines(leftContent, rightContent);
    var rewrite = pcaIsRewrite(diff);

    if (rewrite) {
        // 完全重写：左右并排
        return '<div style="padding:8px;">'
            + '<div style="color:'+pcaC.gold+';font-size:11px;margin-bottom:8px;font-weight:600;">⚠️ 内容几乎完全重写（相同部分 < 20%），左右并排展示：</div>'
            + '<div style="display:flex;gap:10px;">'
            + '<div style="flex:1;min-width:0;">'
            + '<div style="font-size:10px;color:'+pcaC.diffDelText+';margin-bottom:4px;font-weight:600;">◀ 左侧（旧）</div>'
            + '<div style="background:'+pcaC.diffDel+';border:1px solid '+pcaC.diffDelBorder+';border-radius:6px;padding:8px 10px;max-height:250px;overflow-y:auto;font-size:11px;line-height:1.6;color:'+pcaC.diffDelText+';white-space:pre-wrap;word-break:break-all;">'+pcaEsc(leftContent)+'</div>'
            + '</div>'
            + '<div style="flex:1;min-width:0;">'
            + '<div style="font-size:10px;color:'+pcaC.diffAddText+';margin-bottom:4px;font-weight:600;">▶ 右侧（新）</div>'
            + '<div style="background:'+pcaC.diffAdd+';border:1px solid '+pcaC.diffAddBorder+';border-radius:6px;padding:8px 10px;max-height:250px;overflow-y:auto;font-size:11px;line-height:1.6;color:'+pcaC.diffAddText+';white-space:pre-wrap;word-break:break-all;">'+pcaEsc(rightContent)+'</div>'
            + '</div></div></div>';
    }

    // 正常逐行diff
    var html = '<div style="padding:8px;">';
    html += '<div style="color:'+pcaC.gold+';font-size:11px;margin-bottom:6px;font-weight:600;">📝 内容差异（<span style="color:'+pcaC.diffDelText+'">红色=删除</span> <span style="color:'+pcaC.diffAddText+'">绿色=新增</span>）：</div>';
    html += '<div style="background:'+pcaC.input+';border:1px solid '+pcaC.border+';border-radius:6px;padding:8px 0;max-height:300px;overflow-y:auto;font-size:12px;line-height:1.7;font-family:Consolas,monospace;">';

    diff.forEach(function(d) {
        var prefix, bg, color;
        if (d.type === 'add') { prefix = '+'; bg = pcaC.diffAdd; color = pcaC.diffAddText; }
        else if (d.type === 'del') { prefix = '-'; bg = pcaC.diffDel; color = pcaC.diffDelText; }
        else { prefix = ' '; bg = 'transparent'; color = pcaC.dim; }
        html += '<div style="background:'+bg+';padding:1px 10px;color:'+color+';white-space:pre-wrap;word-break:break-all;">'
            + '<span style="display:inline-block;width:16px;opacity:0.6;user-select:none;">'+prefix+'</span>'
            + pcaEsc(d.text || ' ')
            + '</div>';
    });

    html += '</div>';

    // 统计
    var addCount = 0, delCount = 0;
    diff.forEach(function(d) { if (d.type==='add') addCount++; if (d.type==='del') delCount++; });
    html += '<div style="margin-top:6px;font-size:11px;color:'+pcaC.dim+';">';
    if (addCount) html += '<span style="color:'+pcaC.diffAddText+';">+'+addCount+' 行新增</span> ';
    if (delCount) html += '<span style="color:'+pcaC.diffDelText+';">-'+delCount+' 行删除</span>';
    html += '</div></div>';

    return html;
}

