        var res = await fetch('/api/presets/save-openai', { method:'POST', headers:pcaGetHeaders(), body:JSON.stringify(body) });
        if (res.ok) { pcaLog('保存: '+name); try { var ctx = SillyTavern.getContext(); if (ctx.saveSettingsDebounced) ctx.saveSettingsDebounced(); } catch(e) {} return true; }
    } catch(e) {}
    try {
        var res2 = await fetch('/api/presets/save', { method:'POST', headers:pcaGetHeaders(), body:JSON.stringify({apiId:'openai',name:name,preset:preset}) });
        if (res2.ok) return true;
    } catch(e) {}
    return false;
}

