        var wasModified = (curRight !== origRight); // 是否被改过

        html += '<div style="background:'+pcaC.card+';border:1px solid '+(synced?'rgba(110,207,138,0.3)':pcaC.border)+';border-radius:10px;padding:12px 16px;margin-bottom:10px;">';

