        html += '<div style="flex:1;"><span style="color:'+pcaC.dim+';">左(旧)：</span><span style="color:'+(d.left.enabled?pcaC.pink:pcaC.off)+';font-weight:600;">'+(d.left.enabled?'● ON':'○ OFF')+'</span></div>';
