        html += '<span data-pca-action="view" data-pca-idx="'+i+'" data-pca-side="left" style="font-size:11px;color:'+pcaC.dim+';background:transparent;border:1px solid '+pcaC.border+';border-radius:4px;padding:3px 10px;cursor:pointer;">👁 左侧内容</span>';
