        html += '<span data-pca-action="view" data-pca-idx="'+i+'" data-pca-side="diff" style="font-size:11px;color:'+pcaC.gold+';background:rgba(212,168,83,0.1);border:1px solid '+pcaC.goldDim+';border-radius:4px;padding:3px 10px;cursor:pointer;">⚡ 差异对比</span>';
        html += '</div>';
        html += '<div id="pca-pv-'+i+'" style="display:none;margin-top:8px;"></div>';
        html += '</div>';
    });
