}

function pcaRenderNews() {
    var wrap = pcaQ('#pca-content');
    if (!wrap) return;
    if (pcaState.newItems.length === 0) {
        wrap.innerHTML = '<div style="text-align:center;padding:30px;color:'+pcaC.dim+';">没有新增条目</div>';
